var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"KNIGHT_PRIDE_NPC_A","text":{"KOREA":"크륵, 크으으……!","JPN":"グルル、グウウ……！","ENG":"Grrr, Khhhkkk...!","TWN":"咳呃，咳呃呃……！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_COMBAT_MONSTER_PAWN_DAMAGE_DOWN"},{"id":"L3_1","type":"dialog","speaker":"KNIGHT_NPC_ZODIAC_B","text":{"KOREA":"구원이…… 구원을 위해……!","JPN":"救いが……救いのために……！","ENG":"Salvation... For salvation...!","TWN":"為了……為了救贖……！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_ZODIAC_B","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_MONSTER_PAWN_DAMAGE_DOWN"},{"id":"L5_1","type":"dialog","speaker":"NINA_FRONTIER_NULL_NULL","text":{"KOREA":"공개 회선으로 전한다! 적들의 상태가 갑자기 이상해졌어!","JPN":"公開回線を通じて伝える！　敵の様子が急におかしくなった！","ENG":"Announcing through public channel! The enemy is acting strange!","TWN":"這是來自公共頻道的通知——敵人的狀態突然變得很奇怪！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NINA_FRONTIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L6_1","type":"dialog","speaker":"LEE_FRONTIER_NULL_NULL","text":{"KOREA":"절대 거리를 주지 마! 함부로 접근하게 놔뒀다간 뼈도 못 추려!","JPN":"決して距離を詰められるな！　無闇に接近しようものならひとたまりもない！","ENG":"Do not let them get close! The minute they close in, you won't stand a chance!","TWN":"不要給他們縮短距離的機會！要是放任他們接近，後果很危險！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEE_FRONTIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L11_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"침식체로서 본색을 드러내기 시작했네요.","JPN":"侵食体としての本性を現し始めましたね。","ENG":"They started to reveal their true forms as C.O.s.","TWN":"終於開始露出侵蝕體的真面目了。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"진형은 흐트러지지 않는 걸 봐선… 적의 지휘관이 전황을 위험하다고 판단한 거겠죠.","JPN":"陣形が崩れていないということは……敵の指揮官が戦況を危ないと判断したんでしょうね。","ENG":"Seeing that their formation is intact... Their commander must have considered this situation as a threat.","TWN":"但是隊形還沒有散開……就表示敵人的指揮官認為戰況危急吧？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KNIGHT_PRIDE_NPC_A","text":{"KOREA":"대체 뭐야? 갑옷도 무기도, 우리와 똑같아.","JPN":"いったいなんだ？　鎧も武器も、俺たちとそっくりだ。","ENG":"What is that? They have the same weapons and armor as us.","TWN":"究竟是怎麼回事？鎧甲還有武器，都和我們一模一樣。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KNIGHT_PRIDE_NPC_A","text":{"KOREA":"역시 레드시프트 놈들이 관여한 것 아닐까?","JPN":"やっぱりレッドシフトの連中が関与しているんじゃ？","ENG":"Maybe Red Shift did interfere with this.","TWN":"他們會不會是紅移的那些傢伙？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KNIGHT_PRIDE_NPC_A","text":{"KOREA":"아무리 그 자들이라도 그렇지, 이건 너무 지나치잖아…….","JPN":"さすがの奴らでも、これは酷すぎるぜ……","ENG":"But this is too much, even for them...","TWN":"就算是那些人，這樣也太過分了吧……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"……차마 눈 뜨고 볼 수 없군. 이건 기사의 정신을 모욕하는 행위다.","JPN":"……目も当てられないな。これは騎士の精神を侮辱する行為だ。","ENG":"...I can't bear to look at this. This is an insult to chivalry.","TWN":"……如此行徑，這是對騎士精神的侮辱。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"단장님, 흔들리지 마십시오. 평기사들이 더 동요할 겁니다.","JPN":"団長、落ち着いてください。平騎士たちの動揺を煽ってしまいます。","ENG":"Stay composed, Captain. The knight bachelors might get affected.","TWN":"團長，請不要動搖，否則會影響到平民騎士的士氣。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"지금 가장 돌파력이 우수한 태스크포스는 그쪽인 것 같군요.","JPN":"今最も突破力が優秀なタスクフォースはそちらのようですね。","ENG":"You seem to be the TASKFORCE best equipped to break through.","TWN":"現在突破能力最強的特遣勢力就是你們了。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_STATE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"AIRBORNE_STATE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"적진 중심에 이 <color=#ffd34c>침식체 군집</color>을 지휘하는 개체가 있어요.","JPN":"敵陣の中心にこの<color=#ffd34c>侵食体の群れ</color>を指揮している個体がいます。","ENG":"There is an individual entity that's controlling the <color=#ffd34c>C.O. horde</color> in the middle of enemy territory.","TWN":"敵營中一定存在著指揮這個<color=#ffd34c>侵蝕體群</color>的個體。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_STATE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"AIRBORNE_STATE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그 개체를 제압해야 합니다. 적어도 휘하 개체들을 통제하기 어렵게 만들어야 해요.","JPN":"その個体を制圧しなければなりません。少なくとも個体のコントロールを難しくする必要があります。","ENG":"We must take down that entity. We have to make it hard for it to control its underlings, at least.","TWN":"必須制伏那個個體。至少要讓他沒辦法指揮手下的個體才行。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_STATE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"AIRBORNE_STATE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"성공한다면 지금과 같이 통일된 움직임은 막을 수 있을 거랍니다.","JPN":"成功すれば今のように、統率の取れた動きはできなくできるでしょう。","ENG":"If we succeed, we will be able to stop their unified attacks.","TWN":"成功的話，就能阻止現在這樣統一的行動了。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_STATE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"AIRBORNE_STATE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"……알겠다. 길을 여는 건 그대의 힘을 믿도록 하지.","JPN":"……わかった。道を開けるのは君の力を信じよう。","ENG":"...Affirmative. I'll count on you to make an opening.","TWN":"……好，開路的事我就先相信你。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"기사단, 돌격 태세로 진형을 정비하라!","JPN":"騎士団、突撃の態勢を取り、陣形を整えろ！","ENG":"Knights, change formation to charging position!","TWN":"騎士團，突擊隊形！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"진형을 유지해라! 적이 급조된 연합인 이상, 보급이 떨어지면 전력이 크게 약화될 거다!","JPN":"陣形を保て！　敵が急ごしらえの連合である以上、補給が切れたら戦力は著しく低下するはずだ！","ENG":"Hold formation! The enemy's alliance is makeshift. Once they're out of supplies, they will collapse!","TWN":"保持隊型！既然敵人是臨時組成的聯盟，一旦補給耗盡，他們的戰力就會大幅削弱！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"적이 우리보다 우위를 지닌 건 장거리에서 펼치는 화력 지원이다.","JPN":"敵が私たちより優れているのは、長距離からの火力支援だ。","ENG":"Our enemies excel in long-range firepower.","TWN":"敵人在遠距離火力上更具有優勢。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"공중 전력으로 적의 함선들을 우선 공략한다!","JPN":"空中戦力で敵の艦船を優先的に攻略する！","ENG":"Take down the ships using the aerial units first!","TWN":"先利用空中的戰鬥力量攻擊敵人的艦船！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"놈들을 갈기갈기 찢어 버리겠습니다! 지켜봐 주십시오!","JPN":"連中を引き裂いてみせましょう！　お任せください！","ENG":"We will rip them into pieces! Trust us!","TWN":"我要把他們撕成碎片！看著吧！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"8번대, 9번대는 우회하여 적의 보급로를 차단한다. 서두르도록.","JPN":"八番隊、九番隊は迂回して敵の補給路を遮断する。急げ。","ENG":"Squad 8 and 9, turn and block their supply route. Hurry.","TWN":"第8小隊、第9小隊，繞路切斷敵人的補給線，抓緊時間。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"크륵…… 크으……!","JPN":"グルル……くぅ……！","ENG":"Krrrrrr... Khhh...!","TWN":"咳呃……咳呃……！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_23"},{"id":"L38_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"지시대로, 따르겠습…… 니다……!","JPN":"指示通りに、遂行いたし……ます……！","ENG":"Y-yes... sir...!","TWN":"遵……遵……命！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"……미안하다. 너희들의 참혹한 모습은 여기에 모두 묻어 두겠다.","JPN":"……すまない。君たちの残酷な姿はここにすべて埋めよう。","ENG":"...I'm sorry. Your current state will be buried here.","TWN":"……對不起，你們如今慘不忍睹的樣子，都埋在這裡吧。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"알렌 경! 보고드립니다!","JPN":"バーミンガム卿！　報告します！","ENG":"Sir Allen! Reporting!","TWN":"報告艾倫卿！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"기사 흉내를 내는 이방인들이 오고 있습니다! 명령을!","JPN":"騎士を真似た異邦人が向かってきています！　ご命令を！","ENG":"Outsiders who are mimicking chivalry are coming! Give us your orders!","TWN":"有一群模仿騎士的外邦人正朝而來！請下令！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"기사 흉내라고?","JPN":"騎士の真似だと？","ENG":"Mimicking chivalry?","TWN":"模仿騎士？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_A","text":{"KOREA":"크아악!!","JPN":"ぐあぁ！！","ENG":"Aaaargh!","TWN":"呵啊啊！！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_B","text":{"KOREA":"이 빌어먹을 이방인 년……! 죽여 버린다!! 죽여 버리겠어!!","JPN":"このクソッたれの異邦人の小娘め……！　殺す！！　殺してやる！！","ENG":"You damn outsider...! I'll kill you! I'll kill you!!","TWN":"可惡的外邦人……！去死！！去死吧！！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_NULL_B","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_21"},{"id":"L50_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"……버밍엄 교수님.","JPN":"……バーミンガム教授。","ENG":"...Professor Birmingham.","TWN":"……伯明罕教授。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"슈발리에 단장……?","JPN":"シュヴァリエ団長……？","ENG":"Captain Chevalier...?","TWN":"艾斯特洛索團長……？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"어째서 여기에 온 거지? 조디악 나이츠는 관리국의 지원이 우선이지 않나?","JPN":"どうしてここに？　ゾディアックナイツは管理局への支援を優先するはずじゃ？","ENG":"Why are you here? Aren't the Zodiac Knights in charge of supporting the Administration?","TWN":"你怎麼會來這裡？十二宮騎士團不是一向優先支援管理局嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"본래라면 회의장의 경호를 위해 남아 있었을 겁니다.","JPN":"本来なら会議場に警護のために残っていたと思います。","ENG":"Yes, normally we would have stayed to secure the conference room.","TWN":"我本來應該為了會場的警戒工作而留下的。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"교수님 소식을 듣지 않았다면 말입니다.","JPN":"教授のことを聞いてなかったら。","ENG":"If we hadn't heard of your news, that is.","TWN":"要不是聽到教授的消息。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"지금 무슨 짓을 하고 계신 겁니까?","JPN":"いったい今何をされているんですか？","ENG":"What are you doing?","TWN":"你現在是在做什麼？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"기사의 탈을 쓴 괴물들을 부리면서……. 이런 게…….","JPN":"騎士の面を被った化け物を指揮して……こんなの……","ENG":"You are ordering around monsters disguised as knights... Is this...","TWN":"控制那些戴著騎士面具的怪物……這……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"이런 게 당신이 말하던 기사입니까?","JPN":"こんなのがあなたの言っていた騎士なんですか？","ENG":"Is this what you call knights?","TWN":"這就是你說的騎士精神嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"윽……!","JPN":"うっ……！","ENG":"Ugh...!","TWN":"呃……！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"……이게 내 대답일세, 슈발리에 단장.","JPN":"これが私の答えだ、シュヴァリエ団長。","ENG":"...That will be my reply, Captain Chevalier.","TWN":"……這就是我的回答，艾斯特洛索團長。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"왜 이런 생지옥에 함부로 발을 들이밀었나?","JPN":"なぜこのような生き地獄に無闇に足を踏み入れた？","ENG":"Why did you step into this hellhole?","TWN":"你為什麼要自己踏進地獄呢？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"자네와 자네의 친구들은…… 이상적인 기사단 놀이에 심취해 있으면 그만이었던 것을.","JPN":"君と君の仲間たちは……理想の騎士団ごっこに酔いしれているだけで十分だったのに。","ENG":"You should've... stayed occupied with playing knight with your peers.","TWN":"你和你的朋友們……沉醉在理想的騎士團遊戲裡就好了。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"놀이가 아닙니다!","JPN":"騎士ごっこなどではありません！","ENG":"We are not playing around!","TWN":"那不是遊戲！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"아니, 놀이일세.","JPN":"いや、それは騎士ごっこだ。","ENG":"Yes, you are.","TWN":"不，就是遊戲。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"별의 인도자는 낙오자였고 패배자였다.","JPN":"星の導き手は落ちこぼれで、敗北者だった。","ENG":"The Star Guide was a failure and a loser.","TWN":"星之引導者曾經是落伍者和失敗者。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"그녀가 만든 별의 무구는 멸망을 막는 데 조금도 기여하지 못했어.","JPN":"彼女が作った星の武具は滅亡を止めるのに少しも役に立たなかった。","ENG":"Her Star Armament did not contribute at all to saving the world from damnation.","TWN":"她製作的星之武具在阻止滅亡時一點貢獻都沒有。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"그게 무슨……!","JPN":"それはどういう……！","ENG":"What are you...!","TWN":"你那是什麼意思……！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"……큭!?","JPN":"……くっ！？","ENG":"...Kgh?!","TWN":"……呃！？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"이미 눈치채지 않았나. 자네가 믿어 마지않는 기사단의 원류가 무엇으로부터 비롯되었는지.","JPN":"すでに気づいているのではないか。君が信じてやまない騎士団の起源が何なのかを。","ENG":"You haven't figured it out yet? The truth behind the Order you hold so dear?","TWN":"你難道還沒有察覺嗎？你所深信不疑的騎士團的起源究竟是什麼。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"별의 인도라는 건 전부 허상일세. 자네들이 걸어가는 길의 끝에는…….","JPN":"星の導きなどすべて虚像に過ぎない。君たちの歩む道の先には……","ENG":"The Star Guide is all an illusion. And the path you're following...","TWN":"所謂星之引導者不過是虛幻。你們所走的路的盡頭是……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"결국, 아무것도 남아있지 않아.","JPN":"何もないのだ。","ENG":"Leads to nothing.","TWN":"最終，什麼都不會留下。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"단장님!!","JPN":"団長！！","ENG":"Captain!","TWN":"團長！！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"접근하면 안 됩니다, 한솔 경! 저런 공격에 잘못 휘말렸다간 목숨을 장담할 수 없어요!","JPN":"近寄ってはいけません、ヤガミ卿！　あんな攻撃に巻き込まれたら命がどうなるかわかりません！","ENG":"You mustn't approach there, Sir Hansol! Those attacks might cost you your life!","TWN":"不可以過去，楊瀚！不小心被那樣的攻擊掃到，你可能會沒命的！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"하지만 부단장님, 단장님이……!","JPN":"でも副団長、団長が……！","ENG":"But Deputy, the Captain is...!","TWN":"可是副團長，團長她……！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L30_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"하아…… 하……","JPN":"はあ……はぁ……","ENG":"*Huff...* *Huff...*","TWN":"哈啊……哈……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"자네는…… 적어도 자네는 여기 와서는 안 됐어.","JPN":"君は……少なくとも君はここに来てはいけなかった。","ENG":"You... You of all people. You shouldn't have come here.","TWN":"你……不該來這裡。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"그렇지 않았다면 뭔가 오해가 있었을 거라고, 사람들이 잘못 생각했을 거라고 여겼겠지.","JPN":"来なければ、何か誤解があったはずだと、みんなは誤解しているだけだと思えただろう。","ENG":"If you hadn't, you would have thought that there was a misunderstanding.","TWN":"如果你沒有出現，或許會把這裡所發生的一切當作一場誤會。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"그리고 지금까지처럼 기사의 길을 걸었을 걸세.","JPN":"そして今まで通りに、騎士の道を歩んでいたはずだ。","ENG":"And you would have continued on, living your life as a knight.","TWN":"應該還是會像以前這樣，走著騎士之路吧。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"운이 좋다면, 그 앞에 실패가 기다린다는 사실은 모르는 채 숨을 거뒀을 수도 있었겠지.","JPN":"運が良ければ、その先に失敗が待っているという事実を知らないまま死んでいたかもしれん。","ENG":"If you got lucky enough, you would have died not knowing that failure was ahead of you.","TWN":"甚至運氣再好一點，在失敗還沒有到達眼前的情況下就停止呼吸。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"그렇다면…….","JPN":"それなら……","ENG":"Then...","TWN":"這樣的話……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"언젠가 이곳에도 닥칠 멸망에 대비할 수 있는 희망을…….","JPN":"いつかこの世界にも迫るであろう滅亡に備えることができるよう、希望を……","ENG":"Maybe that's why she planted hope for the future...","TWN":"為這個總有一天會面臨到滅亡的地方，留下希望……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"BATTLE_BOSS_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L38_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"어두운 밤에 길 잃고 헤매는 이들을 인도해 줄 별빛을 남기기로.","JPN":"闇夜で道に迷っている者たちを導く星の光を残そうと。","ENG":"She left the starlight to guide the lost back to the right track.","TWN":"為那些在暗夜中迷路的人，留下指引的星光。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"BATTLE_BOSS_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"그렇다면 그 말은…… 대체 뭐였습니까?","JPN":"そう言っていたのは……いったいなんだったんですか？","ENG":"Then... Why did you say those words?","TWN":"那句話……究竟又是什麼意思？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L41_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"잘 기억하고 있군. 자네는 분명 좋은 학생이야.","JPN":"よく覚えているな。君は確かに良い学生だ。","ENG":"You remember it well. It is clear that you are an excellent student.","TWN":"你記得很清楚啊，你的確是個好學生。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"하지만 슈발리에 단장, 현실은 다르다네.","JPN":"しかしシュヴァリエ団長、現実はそうではない。","ENG":"But Captain Chevalier, reality is different from our expectations.","TWN":"不過艾斯特洛索團長，現實不一樣。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"희망에 홀린 자들일수록 더욱 고통스러운 최후를 맞이하고.","JPN":"希望を見た者ほど、より苦しい最期を迎えることになり。","ENG":"Those who are hopeful are met with a painful demise.","TWN":"越是沉迷於希望的人，其結局越痛苦。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"별빛의 인도를 따르던 이들은 낭떠러지에 마주쳐 좌절하게 되어 있지.","JPN":"星の光の導きに従っていた者たちは、最後が崖だと知り絶望する運命だ。","ENG":"And those under the guidance of the stars fall and perish.","TWN":"同樣，追隨星之指引的人們在懸崖峭壁面前也必會摔得粉身碎骨。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"그건……! 그런 건……!","JPN":"それは……！　そんなことは……！","ENG":"That's... That's...!!","TWN":"那……！那是……！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"……자네는 주위에서 광대라고 조롱해도 떳떳했지.","JPN":"……君は周りからピエロだとあざ笑われても、自分を貫いていたな。","ENG":"...You were always dignified, even when everyone mocked you as being a clown.","TWN":"……就算被周圍的人嘲笑是小丑，你也曾經是理直氣壯的吧。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"차라리 광대로 남게. 이런 현실을 바꾸려고 하지 말고.","JPN":"いっそピエロのまま残れ。このような現実を変えようとするくらいなら。","ENG":"You'd be better off as a clown. Do not try to change this cruel reality.","TWN":"為什麼不做好那樣的小丑呢，不要試圖改變這樣的現實。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"만약 그럴 수 없다고 한다면…….","JPN":"もしそれが出来ないと言うなら……","ENG":"If you say that you can't...","TWN":"如果你說做不到的話……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L1_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"오늘 이 자리에서, 내일의 새벽을 맞이할 수 없게 만들어 주겠네.","JPN":"今日この場で、明日の夜明けを迎えられないようにするまでだ。","ENG":"I will make you not be able to see the dawn of tomorrow here today.","TWN":"那今天在這裡，我會讓你看不到明天的太陽。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};